import mongoose from 'mongoose';
import dotenv from 'dotenv';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
dotenv.config({ path: path.resolve(__dirname, '../.env.local') });
dotenv.config({ path: path.resolve(__dirname, '../.env') });

const MONGO_URI = process.env.MONGO_URI;
if (!MONGO_URI) { console.error('MONGO_URI not found'); process.exit(1); }

const examCategorySchema = new mongoose.Schema({
  name: { type: String, required: true, trim: true },
  type: { type: String, enum: ['Central', 'State'], required: true },
  description: { type: String, trim: true }
}, { timestamps: true });

const examSchema = new mongoose.Schema({
  category: { type: mongoose.Schema.Types.ObjectId, ref: 'ExamCategory', required: true },
  name: { type: String, required: true, trim: true },
  code: { type: String, required: true, uppercase: true, trim: true },
  description: { type: String, trim: true },
  isActive: { type: Boolean, default: true },
  logo: { type: String }
}, { timestamps: true });

const examPatternSchema = new mongoose.Schema({
  exam: { type: mongoose.Schema.Types.ObjectId, ref: 'Exam', required: true },
  title: { type: String, required: true, trim: true },
  duration: { type: Number, required: true, min: 1 },
  totalMarks: { type: Number, required: true, min: 0 },
  negativeMarking: { type: Number, default: 0, min: 0 },
  sections: [{
    name: { type: String, required: true, trim: true },
    totalQuestions: { type: Number, required: true, min: 1 },
    marksPerQuestion: { type: Number, required: true, min: 0 },
    negativePerQuestion: { type: Number, default: 0, min: 0 },
    sectionDuration: { type: Number, min: 0 }
  }]
}, { timestamps: true });

const practiceTestSchema = new mongoose.Schema({
  examPattern: { type: mongoose.Schema.Types.ObjectId, ref: 'ExamPattern', required: true },
  title: { type: String, required: true, trim: true },
  slug: { type: String, lowercase: true, trim: true },
  totalMarks: { type: Number, required: true, min: 0 },
  duration: { type: Number, required: true, min: 1 },
  accessLevel: { type: String, enum: ['FREE', 'PRO'], default: 'FREE' },
  isPYQ: { type: Boolean, default: false },
  pyqYear: { type: Number, default: null },
  pyqShift: { type: String, default: null, trim: true },
  pyqExamName: { type: String, default: null, trim: true },
  publishedAt: { type: Date, default: Date.now },
  questions: [{
    questionText: { type: String, required: true },
    questionImage: { type: String, default: '' },
    options: [{ type: String, required: true }],
    optionImages: [{ type: String, default: '' }],
    correctAnswerIndex: { type: Number, required: true, min: 0 },
    explanation: { type: String, trim: true },
    section: { type: String, required: true, trim: true },
    tags: [{ type: String, trim: true }],
    difficulty: { type: String, enum: ['easy', 'medium', 'hard', 'mixed'], default: 'medium' }
  }]
}, { timestamps: true });

const ExamCategory = mongoose.models.ExamCategory || mongoose.model('ExamCategory', examCategorySchema);
const Exam = mongoose.models.Exam || mongoose.model('Exam', examSchema);
const ExamPattern = mongoose.models.ExamPattern || mongoose.model('ExamPattern', examPatternSchema);
const PracticeTest = mongoose.models.PracticeTest || mongoose.model('PracticeTest', practiceTestSchema);

const REA = 'General Intelligence';
const ENG = 'English Language';
const QA  = 'Quantitative Aptitude';
const GA  = 'General Awareness';

const KEY = [1, 2, 4, 2, 4, 3, 4, 2, 3, 3, 2, 4, 2, 2, 2, 2, 1, 2, 2, 4, 4, 3, 1, 4, 2, 2, 1, 1, 4, 3, 2, 2, 1, 1, 3, 3, 3, 2, 3, 3, 3, 3, 1, 2, 2, 2, 2, 2, 3, 1, 1, 1, 2, 1, 2, 1, 2, 1, 1, 2, 2, 3, 3, 3, 1, 3, 1, 1, 1, 2, 2, 4, 2, 2, 1, 4, 4, 2, 3, 2, 1, 1, 2, 1, 3, 2, 3, 1, 2, 3, 3, 1, 4, 1, 1, 1, 3, 4, 1, 2];
if (KEY.length !== 100) { console.error(`KEY length ${KEY.length}`); process.exit(1); }

const RAW = [
  { s: `General Intelligence`, q: `If BREAD is coded as 35, then how is FLOUR coded?`, o: [`77`, `72`, `75`, `80`], e: `Logic: Sum of place value of letter + 5 = Number For, BREAD - 35 (2 + 18 + 5 + 1 + 4) + 5 = 35 SMimAiPlaPrlIyN, G EXAM TIME UPDATED CREATED S3 ID FLOUIRD - ? TITLE LANGUAGE SUBJECT CATEGORY EXAMS MARKS (MINS) AT AT PAT (6 + 12 + 15 + 21 + 18) + 5 = 77 Thus, correct optioSneleisc(taio).n LENGTH 12, 2026, 28, 2026, Post 00:05:57 14:22:40 Similar Paper (Held on 28 Jul` },
  { s: `General Intelligence`, q: `Find the next letter: A, D, H, M, ?`, o: [`R`, `S`, `T`, `U`], e: `A+3=D, D+4=H, H+5=M, M+6=S. Option B.` },
  { s: `General Intelligence`, q: `Choose the word that does NOT belong to the group.`, o: [`Brother`, `Sister`, `Cousin`, `Neighbor`], e: `Brother, Sister and Cousin are family relationships. Neighbor is not a family relation; it refers to someone who lives nearby. Therefore, Neighbor does not belong to the group. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `6 : 220 :: 5 : ?`, o: [`104`, `129`, `154`, `184`], e: `Given: 6 : 220 :: 5 : ? Logic: 1st number3+ 4 = 2nd number For, 6 : 216 63= 216, 216 + 4 = 220 Similarly, 5:? 53= 125, 125 + 4 = 129 Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `How many meaningful English words can be formed from the letters of "STOP", using each letter once?`, o: [`Four`, `Three`, `Two`, `More than four`], e: `Given: STOP Let's list the meaningful English words formed using S, T, O, P (each letter once): STOP TOPS POTS POST OPTS That makes 5 meaningful words. So, More than four meaningful English words can be formed from the letters. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `If an employee repeatedly misses deadlines, what should a manager do?`, o: [`Ignore the issue`, `Warn immediately`, `Identify cause and guide`, `Terminate service`], e: `Given: If an employee repeatedly misses deadlines. Explanation: A manager should first try to understand why the employee is missing deadlines and help them improve. So, Identify cause and guide should a manager do. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `Identify the number that breaks the series: 5, 10, 17, 26, 38`, o: [`10`, `17`, `26`, `38`], e: `Given: 5, 10, 17, 26, 38 Logic: Numbers are increasing odd number from 5. 5 + 5 = 10 10 + 7 = 17 17 + 9 = 26 26 + 11 = 38 = 37 So, 38 is wrong term. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `Find the next term: 3, 6, 11, 18, ?`, o: [`25`, `27`, `29`, `31`], e: `Given: 3, 6, 11, 18, ? Logic: Numbers are increasing odd number from 3. 3+3=6 6 + 5 = 11 11 + 7 = 18 18 + 9 = 27 So, the missing term is 27. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `A company finds a steady drop in customer satisfaction. What should it do first?`, o: [`Increase prices`, `Fire employees`, `Analyse customer feedback`, `Stop services`], e: `Given: A company finds a steady drop in customer satisfaction. Explanation: When customer satisfaction drops, the first step should be to understand the reason. Checking customer feedback helps the company identify problems and decide what action to take next. So, Analyse customer feedback should it do first. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `Arrange the words in meaningful order: 1. Judge 2. Evidence 3. Crime 4. Verdict`, o: [`3-1-2-4`, `2-3-1-4`, `3-2-1-4`, `1-2-3-4`], e: `Given words: 1. Judge 2. Evidence 3. Crime 4. Verdict Logical order: First, a Crime happens Then Evidence is collected The case goes to a Judge Finally, the Verdict is given So the correct order is: 3 2 1 4 = 3-2-1-4 Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `Which number does NOT belong to the group?`, o: [`121`, `144`, `169`, `196`], e: `121, 169 and 196 are not divisible by 3. 144 is divisible by 3. So, 144 is odd one out. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `Statements: 1. All birds are animals. 2. Some animals can fly. Conclusions: I. Some birds can fly. II. All flying animals are birds.`, o: [`Only I follows`, `Only II follows`, `Both follow`, `Neither follows`], e: `Statements: 1. All birds are animals. 2. Some animals can fly. From the given statements possible Venn diagram will be. Conclusions: I. Some birds can fly. (False, there is no relation between birds and fly). II. All flying animals are birds. (False, this is not stated. Many animals other than birds (like bats or insects) can fly). So, N either follows. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `Statement: "Digital payments reduce the use of cash." Which supports the statement?`, o: [`Cash is difficult to handle`, `Online transactions are faster`, `People prefer cash`, `Banks charge fees`], e: `Given: Statement: "Digital payments reduce the use of cash." Explanation: Faster online transactions encourage people to use digital payments instead of cash, which supports the statement that digital payments reduce the use of cash. So, Online transactions are faster supports the statement. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `You notice incorrect data in an official presentation at your workplace. What should you do?`, o: [`Ignore the error`, `Inform the presenter privately and correct it appropriately`, `Share the mistake publicly`, `Remove the entire presentation`], e: `Given: You notice incorrect data in an official presentation at your workplace. Explanation: It maintains professionalism, corrects the mistake, and avoids embarrassing the presenter. So, Inform the presenter privately and correct it appropriately should you do. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `If the sum of three consecutive even numbers is 66, what is the largest number?`, o: [`22`, `24`, `26`, `28`], e: `Given: If the sum of three consecutive even numbers is 66. Let the three consecutive even numbers be: (x, x + 2, x + 4) Their sum is given as 66: x + (x + 2) + (x + 4) = 66 3x + 6 = 66 3x = 60 x = 20 The numbers are 20, 22, 24. 20 + 22 + 24 = 66 The largest number = 24 So, 24 is the largest number. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `If A = 7, B = 4, C = 3, find: (A × B) - (C + B)?`, o: [`19`, `21`, `23`, `25`], e: `Given: If A = 7, B = 4, C = 3, find: (A × B) - (C + B)? Using BODMAS rule. Symbol [], , () Operation preference wise Brackets (power), (root), of Orders, of Division ÷ Multiplication × Addition + Subtraction - New equation: (7 × 4) - (3 + 4) = ? 28 - 7 = ? ? = 21 Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `Statement: "The road was blocked due to heavy snowfall." Conclusions: I. Traffic was disrupted. II. All roads were blocked.`, o: [`Only I follows`, `Only II follows`, `Both follow`, `Neither follows`], e: `Statement: "The road was blocked due to heavy snowfall." Conclusions: I. Traffic was disrupted. If a road is blocked due to heavy snowfall, it logically leads to traffic disruption. II. All roads were blocked. The statement talks about the road, not all roads. Therefore, only Conclusion I follows. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `If CAT 24 and DOG 26. Then PIG ?`, o: [`30`, `32`, `34`, `36`], e: `Given: If CAT 24 and DOG 26. Logic: Sum of place value of letters = Number For, CAT 24 3 + 1 + 20 = 24 For, DOG 26 4 + 15 + 7 = 26 Similarly, PIG ? 16 + 9 + 7 = 32 So, PIG 32 Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `Four sets of details are given. Two are exactly identical. Identify them. 1. Rakesh Kumar, Sector-15, Noida - 201301 2. Rakesh Kumar, Sector-16, Noida - 201301 3. Rakesh Kumar, Sector-15, Noida - 201301 4. Rakesh Kumar, Sector-15, Noida - 201302`, o: [`1 and 2`, `1 and 3`, `2 and 4`, `3 and 4`], e: `Given: 1. Rakesh Kumar, Sector-15, Noida ­ 201301 2. Rakesh Kumar, Sector-16, Noida ­ 201301 3. Rakesh Kumar, Sector-15, Noida ­ 201301 4. Rakesh Kumar, Sector-15, Noida ­ 201302 Now, we check each options. Option (a): (1 and 2) Sector number is different (Sector-15 Sector-16). Option (b): (1 and 3) Name, sector, city, and pin code are exactly the same. Option (c): (2 and 4) Sector and pin code are different. Option (d): (3 and 4) Pin code is different (201301 201302). So, 1 and 3 are exactly identical. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `Choose the odd pair.`, o: [`14 - 196`, `16 - 256`, `18 - 324`, `20 - 360`], e: `Logic: 1st number2= 2nd number Now, we check each options. Option (a): 14 - 196 142= 196 Option (b): 16 - 256 162= 256 Option (c): 18 - 324 182= 324 Option (d): 20 - 360 202=360 So, 20 - 360 is odd one out. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `Statements: I. All bicycles are vehicles. II. Some vehicles are electric. Which of the following conclusions logically follows from the given statements?`, o: [`Some bicycles are electric`, `All bicycles are electric`, `No bicycle is electric`, `No definite conclusion`], e: `Statements: I. All bicycles are vehicles. II. Some vehicles are electric. From the given statements possible Venn diagram will be. Explanation: There is no direct link between bicycles and electric vehicles. The electric vehicles mentioned may or may not be bicycles. A. Some bicycles are electric. Not certain B. All bicycles are electric. Not stated C. No bicycle is electric. Not stated Therefore, no definite conclusion can be drawn. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `Choose the word most closely related to: Author : Book :: Painter : ?`, o: [`Brush`, `Canvas`, `Painting`, `Gallery`], e: `Given: Author : Book :: Painter : ? An Author creates a Book. Similarly, Painter : ? A Painter creates a Painting. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `Find the missing number: 2, 10, 26, 50, ?, 122`, o: [`82`, `90`, `94`, `98`], e: `Given: 2, 10, 26, 50, ?, 122 Logic: Difference is increasing multiple of 8. 2 + 8 = 10 10 + 16 = 26 26 + 24 = 50 50 + 32 = 82 82 + 40 = 122 So, the missing term is 82. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `If + means ×, - means ÷, × means + and ÷ means - Find the value of: 18 + 2 - 4 × 3 ÷ 5?`, o: [`1`, `3`, `5`, `7`], e: `Given: 18 + 2 - 4 × 3 ÷ 5? Given Sign+ - ×÷ New Sign ×÷+ - Using BODMAS rule. Symbol [], , () Operation preference wise Brackets (power), (root), of Orders, of ÷ Division × + Multiplication - Addition Subtraction New equation: 18 × 2 ÷ 4 + 3 - 5 = ? 36 ÷ 4 + 3 - 5 = ? 9+3-5=? 12 - 5 = ? ?=7 Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `Pointing to a girl, Aman said, "She is the daughter of my father's sister." How is the girl related to Aman?`, o: [`Sister`, `Cousin`, `Niece`, `Aunt`], e: `Given: Pointing to a girl, Aman said, "She is the daughter of my father's sister." From the given information blood relation diagram will be. So, the girl is cousin of Aman. Thus, correct option is (b).` },
  { s: `General Awareness`, q: `Which Indian athlete won gold medal at Tokyo Olympics 2021?`, o: [`Bajrang Punia`, `Neeraj Chopra`, `Ravi Dahiya`, `PV Sindhu`], e: `The correct answer is (B) Neeraj Chopra Explanation: · Neeraj Chopra won the gold medal in the men's javelin throw at the Tokyo 2020 Olympics (held in 2021). · He became the second Indian to win an individual Olympic gold medal after Abhinav Bindra. Information Booster: · His gold-winning throw was measured at 87.58 meters. Additional Knowledge: · Bajrang Punia (Option A): Won a Bronze medal in Wrestling. · Ravi Dahiya (Option C): Won a Silver medal in Wrestling. · PV Sindhu (Option D): Won a Bronze medal in Badminton.` },
  { s: `General Awareness`, q: `Assertion (A): Newspapers play a role in shaping public opinion. Reason (R): They provide information and analysis on current issues.`, o: [`Both A and R are true and R explains A`, `Both A and R are true but R does not explain A`, `A is true but R is false`, `A is false but R is true`], e: `The correct answer is (A) Both A and R are true and R explains A Explanation: · Media, including newspapers, is considered the fourth pillar of democracy. · By providing factual information and various perspectives (analysis), newspapers influence how the public perceives governmental policies and social events. Information Booster: · Freedom of the Press in India is implied under Article 19(1)(a) ­ Freedom of speech and expression. Additional Knowledge: · The press acts as a watchdog, highlighting lapses in governance.` },
  { s: `General Awareness`, q: `Which mission focuses on urban water supply and sewerage infrastructure?`, o: [`AMRUT`, `Swachh Bharat Mission`, `Jal Jeevan Mission`, `PMAY-U`], e: `The correct answer is (A) AMRUT Explanation: · AMRUT (Atal Mission for Rejuvenation and Urban Transformation) was launched to provide basic civic amenities like water supply, sewerage, and urban transport in cities. · Its primary purpose is to ensure every household has access to a tap with an assured supply of water and a sewerage connection. Information Booster: · AMRUT 2.0 was launched in 2021 to make cities 'water secure' and provide functional tap connections to all households in statutory towns. Additional Knowledge: · Jal Jeevan Mission (Option C): Primarily focuses on providing functional household tap connections to rural India. · Swachh Bharat Mission (Option B): Focuses on sanitation and waste management.` },
  { s: `General Awareness`, q: `With reference to the South Asian Association for Regional Cooperation (SAARC), consider the following statements: 1. The SAARC Charter was adopted in Dhaka on 8 December 1985. 2. The Secretariat of the Association was established in Kathmandu on 16 January 1987. 3. Afghanistan became the eighth member of SAARC during the 14th Summit held in 2007. Which of the statements given above are correct?`, o: [`1 and 2 only`, `2 and 3 only`, `1 and 3 only`, `1, 2, and 3`], e: `The correct answer is (d) 1, 2, and 3 Explanation: Statement 1 is correct: The South Asian Association for Regional Cooperation (SAARC) was established when its Charter was formally adopted in Dhaka, Bangladesh, on 8 December 1985. Statement 2 is correct: While the association was founded in 1985, the SAARC Secretariat was established later in Kathmandu, Nepal, on 16 January 1987 to coordinate and monitor the implementation of activities. Statement 3 is correct: Originally, SAARC had seven founding members (Bangladesh, Bhutan, India, the Maldives, Nepal, Pakistan, and Sri Lanka). Afghanistan joined as the eighth member during the 14th SAARC Summit held in New Delhi in 2007. Information Booster: The primary objective of SAARC is to promote the welfare of the peoples of South Asia and to imp` },
  { s: `General Awareness`, q: `Consider the following statements: Statement 1: Literacy rate is higher in urban areas than rural areas. Statement 2: Urban areas have better access to educational institutions.`, o: [`Only 1`, `Only 2`, `Both 1 and 2`, `Neither`], e: `The correct answer is (C) Both 1 and 2 Explanation: · According to various census data, urban literacy rates are consistently higher than rural rates in India. · The availability of better schools, colleges, coaching centers, and higher awareness levels in cities contributes to this disparity. Information Booster: · Kerala has the highest literacy rate in India, while Bihar has the lowest (as per Census 2011). Additional Knowledge: · Literacy is defined as the ability to read and write with understanding in any language for a person aged 7 and above.` },
  { s: `General Awareness`, q: `Which of the following are outputs of the iron and steel industry?`, o: [`1 and 2 only`, `1, 2 and 4 only`, `2 and 3 only`, `1, 3 and 4 only`], e: `The correct answer is (B) 1, 2 and 4 only Explanation: · The iron and steel industry produces steel, which is used as a primary material for many other products. · Typical outputs include machinery, construction materials (beams/rods), and transport equipment. Information Booster: · It is often called the 'backbone of modern industry' because almost everything we use is either made of iron or steel or has been made with tools and machinery of these metals. Additional Knowledge: · This industry is a feeder industry whose products are used as raw materials for other industries.` },
  { s: `General Awareness`, q: `What is the primary objective of ISRO's upcoming human spaceflight programme?`, o: [`Establishing a lunar base`, `Sending astronauts into low Earth orbit`, `Exploring Mars with crewed mission`, `Deploying a space telescope`], e: `The correct answer is (B) Sending astronauts into low Earth orbit Explanation: · The Gaganyaan mission aims to demonstrate indigenous capability to undertake human space flight to Low Earth Orbit (LEO). · It plans to send a crew of 3 members to an orbit of 400 km for a 3-day mission. Information Booster: · LVM3 rocket (GSLV Mk III) is the launch vehicle identified for the Gaganyaan mission. Additional Knowledge: · Exploring Mars (Option C): Mangalyaan (MOM) was a robotic orbiter mission, not a crewed one. · Establishing a lunar base (Option A): While Chandrayaan missions explore the moon, a base is a much later objective.` },
  { s: `General Awareness`, q: `Which of the following products are NOT derived from the Agro-based sector? 1. Rayon 2. Jute Textiles 3. Nylon 4. Edible Oil`, o: [`1 and 3 only`, `2 and 4 only`, `3 only`, `1, 2, and 3`], e: `The correct answer is (a) 1 and 3 only Explanation: · Agro-based industries use plant and animal-based raw materials. · Jute Textiles are derived from jute fibre, which is obtained from jute plants. · Edible Oil is extracted from oilseeds like mustard, groundnut, and sunflower. · Rayon is a semi-synthetic fibre made from wood pulp through chemical processing and is classified under the chemical industries. · Nylon is a fully synthetic fibre made from petrochemicals and belongs to the petrochemical industry. Information Booster: · Agro-based industries include cotton textiles, jute textiles, sugar, edible oil, and food processing industries. · Mineral-based industries use mineral ores as raw materials, while chemical and petrochemical industries produce synthetic products like nylon. Additi` },
  { s: `General Awareness`, q: `Assertion (A): Gandhara art shows Greco-Roman influence. Reason (R): Gandhara sculptures use realistic human anatomy.`, o: [`Both A and R are true, and R is the correct explanation of A`, `Both A and R are true, but R is not the correct explanation of A`, `A is true, but R is false`, `A is false, but R is true`], e: `The correct answer is (A) Both A and R are true, and R is the correct explanation of A Explanation: · The Gandhara School of Art is often called the Indo-GreeCkospcyhroigohltb©ec2a0u2se6 iAt dadpap2li4e7d Greek techniques to Indian subjects. · The use of realistic musculature, curly hair, and drapery folds are direct influences of Greco-Roman realism. Information Booster: · This school flourished during the Kushana period, particularly under Kanishka. Additional Knowledge: · Mathura School (Contrast): Developed indigenously and used red sandstone, focusing more on spiritual symbolism than physical realism.` },
  { s: `General Awareness`, q: `Eskers are formed due to:`, o: [`Ice erosion`, `Wind deposition`, `Subglacial meltwater deposition`, `Volcanic activity`], e: `The correct answer is (C) Subglacial meltwater deposition Explanation: · Eskers are long, winding ridges of stratified sand and gravel. · They are formed by streams of meltwater flowing through tunnels within or beneath glaciers. Information Booster: · Eskers are part of 'fluvioglacial' landforms. Additional Knowledge: · Ice erosion (Option A): Leads to features like Cirques, U-shaped valleys, and Fiords. · Wind deposition (Option B): Leads to features like Sand dunes and Loess.` },
  { s: `General Awareness`, q: `According to India's Environment Report, which sector contributes most to emissions?`, o: [`Agriculture`, `Transport`, `Energy`, `Waste`], e: `The correct answer is (C) Energy Explanation: · The energy sector (including electricity production and heating) is the largest contributor to greenhouse gas emissions in India. · This is primarily due to the heavy reliance on coal for power generation. Information Booster: · India has committed to achieving 'Net Zero' emissions by the year 2070. Additional Knowledge: · Agriculture (Option A): Contributes significantly to methane emissions (paddy fields, livestock). · Transport (Option B): A growing sector for emissions, especially CO2 from fossil fuels.` },
  { s: `General Awareness`, q: `Which statement about India's performance at Asian Athletics Championships 2025 is correct?`, o: [`India topped medal tally`, `India won no gold medals`, `India secured medals in relay events`, `India finished last`], e: `The correct answer is (C) India secured medals in relay events Explanation: · Indian athletes have historically been strong in relay events (4x400m) at the Asian level. · In recent championships, the relay teams have consistently reached the podium. Information Booster: · The Asian Athletics Association is the governing body for the sport of athletics in Asia. Additional Knowledge: · Medal Tally (Option A): Usually dominated by China or Japan. · Gold Medals (Option B): India usually wins several gold medals in categories like Javelin, Steeplechase, and Shot Put.` },
  { s: `General Awareness`, q: `For which field was a noted author awarded Padma Shri 2025?`, o: [`Sports`, `Literature and Education`, `Science`, `Social work`], e: `The correct answer is (B) Literature and Education Explanation: · Padma Shri is the fourth-highest civilian award in India. · For authors and poets, the award is strictly conferred under the category of 'Literature and Education'. Information Booster: · Padma Awards are announced annually on the eve of Republic Day (January 26). Additional Knowledge: · Social Work (Option D): Awarded to those making significant contributions to society/marginalized groups. · Sports (Option A): Awarded to elite athletes and coaches.` },
  { s: `General Awareness`, q: `Statement 1: Migration contributes to urbanisation. Statement 2: Cities offer better employment opportunities.`, o: [`Only 1`, `Only 2`, `Both 1 and 2`, `Neither`], e: `The correct answer is (C) Both 1 and 2 Explanation: · Rural-to-urban migration is a primary driver of the growth of city populations (urbanisation). · The 'Pull Factor' of cities includes better job prospects, infrastructure, and healthcare. Information Booster: · In India, the percentage of the urban population has been steadily increasing, currently over 31% as per the last census. Additional Knowledge: · Push Factors: Factors like agricultural distress or lack of facilities in villages that force people to migrate.` },
  { s: `General Awareness`, q: `Which of the following goods does NOT violate the law of demand?`, o: [`Giffen goods`, `Veblen goods`, `Normal goods`, `Speculative goods`], e: `The correct answer is (C) Normal goods Explanation: · The Law of Demand states that, other factors being equal, price and quantity demanded are inversely related (as price rises, demand falls). · Normal goods follow this law strictly. Information Booster: · For normal goods, the demand also increases as the consumer's income increases. Additional Knowledge: · Giffen Goods (Option A): Inferior goods where demand increases as price increases (violates the law). · Veblen Goods (Option B): Luxury goods where high price increases the status/demand (violates the law).` },
  { s: `General Awareness`, q: `The Employment Assurance Scheme (EAS) was launched during which Five-Year Plan?`, o: [`Sixth`, `Seventh`, `Eighth`, `Ninth`], e: `The correct answer is (C) Eighth Explanation: · The Employment Assurance Scheme (EAS) was launched on October 2, 1993, which falls within the Eighth Five-Year Plan (1992-1997). · It aimed to provide gainful employment during the lean agricultural season in drought-prone, tribal, and hill areas. Information Booster: · The Eighth Plan was significant for focusing on human resource development and the introduction of New Economic Policy reforms. Additional Knowledge: · Seventh Plan (Option B): Covered 1985-1990; Jawahar Rozgar Yojana was launched in 1989. · Sixth Plan (Option A): Covered 1980-1985; focused on poverty eradication (Garibi Hatao).` },
  { s: `General Awareness`, q: `\`One Nation One Tax' refers to:`, o: [`Income Tax`, `Corporate Tax`, `GST`, `Customs Duty`], e: `The correct answer is (C) GST Explanation: · Goods and Services Tax (GST) was launched with the slogan 'One Nation, One Tax, One Market'. · It replaced multiple indirect taxes like Excise Duty, VAT, and Service Tax to create a unified tax structure. Information Booster: · GST was implemented in India on July 1, 2017. Additional Knowledge: · Income Tax (Option A): Is a direct tax and varies based on individual income brackets. · Corporate Tax (Option B): Is a direct tax levied on the net income of companies.` },
  { s: `General Awareness`, q: `Which of the following laws replaced the Indian Penal Code, 1860?`, o: [`Bharatiya Nyaya Sanhita, 2023`, `Bharatiya Sakshya Adhiniyam, 2023`, `Criminal Law Amendment Act`, `Indian Justice Code`], e: `The correct answer is (A) Bharatiya Nyaya Sanhita, 2023 Explanation: · The Bharatiya Nyaya Sanhita (BNS) replaced the colonial-era Indian Penal Code (IPC) of 1860. · It came into effect on July 1, 2024, bringing changes to definitions of crimes and punishments. Information Booster: · Along with BNS, the BNSS replaced the CrPC, and BSA replaced the Indian Evidence Act. Additional Knowledge: · Bharatiya Sakshya Adhiniyam (Option B): Replaced the Indian Evidence Act, 1872.` },
  { s: `General Awareness`, q: `The Padma Vibhushan is awarded for:`, o: [`Gallantry`, `Distinguished service of exceptional order`, `Sports excellence`, `Academic research only`], e: `The correct answer is (B) Distinguished service of exceptional order Explanation: · Padma Vibhushan is the second-highest civilian award of the Republic of India, after Bharat Ratna. · It is awarded for "exceptional and distinguished service" in any field including service rendered by Government servants. Information Booster: · The Padma awards were instituted in 1954 and are announced every year on Republic Day. Additional Knowledge: · Gallantry (Option A): Awards like Param Vir Chakra or Shaurya Chakra are given for gallantry. · Padma Bhushan is for distinguished service of high order, while Padma Shri is for distinguished service.` },
  { s: `General Awareness`, q: `India is a member of which of the following groupings?`, o: [`NATO`, `QUAD`, `G7`, `OPEC`], e: `The correct answer is (B) QUAD Explanation: · The Quadrilateral Security Dialogue (QUAD) is a strategic forum between Australia, India, Japan, and the United States. · Its primary focus is on maintaining a free and open Indo-Pacific region. Information Booster: · India is also a member of G20, BRICS, and SCO. Additional Knowledge: · NATO (Option A): A military alliance of North American and European countries; India is not a member. · G7 (Option C): India is often invited as a guest but is not a formal member. · OPEC (Option D): An organization of oil-exporting nations; India is a major oil importer.` },
  { s: `General Awareness`, q: `Which gas is mainly responsible for acid rain?`, o: [`Carbon monoxide`, `Sulphur dioxide`, `Methane`, `Ozone`], e: `The correct answer is (B) Sulphur dioxide Explanation: · Acid rain is caused by a chemical reaction that begins when compounds like sulphur dioxide ($SO_2$) and nitrogen oxides are released into the air. · These substances can rise very high into the atmosphere, where they mix and react with water, oxygen, and other chemicals to form acidic pollutants. Information Booster: · Acid rain has a pH level of around 4.2­4.4, whereas normal rain is slightly acidic with a pH of about 5.6. Additional Knowledge: · Acid rain causes damage to buildings (like the Taj Mahal), forests, and aquatic life.` },
  { s: `General Awareness`, q: `In volleyball, how many players are there in each team on the court?`, o: [`Five`, `Six`, `Seven`, `Eight`], e: `The correct answer is (B) Six Explanation: · A standard indoor volleyball game is played with two teams of six players each. · The players are positioned in two rows of three players each. Information Booster: · Beach volleyball, a popular variant, is played with only two players per team. Additional Knowledge: · Basketball (Option A): Typically played with 5 players per team.` },
  { s: `General Awareness`, q: `The Gaganyaan mission is primarily aimed at:`, o: [`Establishing a space station`, `Human spaceflight capability`, `Deep space exploration`, `Satellite navigation`], e: `The correct answer is (B) Human spaceflight capability Explanation: · Gaganyaan is a mission by ISRO to demonstrate indigenous capability to undertake human space flight to Low Earth Orbit (LEO). · It aims to send a crew of 3 members to an orbit of 400 km for a 3-day mission and bring them back safely to earth. Information Booster: · If successful, India will become the fourth nation in the world to launch a manned space mission after the USA, Russia, and China. Additional Knowledge: · Satellite navigation (Option D): This is the domain of NavIC (IRNSS), not Gaganyaan.` },
  { s: `General Awareness`, q: `Which sector received the highest FDI inflow in India in recent years?`, o: [`Agriculture`, `Manufacturing`, `Services`, `Mining`], e: `The correct answer is (C) Services Explanation: · The Services sector, which includes Financial, Banking, Insurance, and Non-financial/Business services, consistently receives the highest Foreign Direct Investment (FDI) inflows in India. · Computer Software and Hardware is another major contributor often grouped within technical services. Information Booster: · FDI is a major source of non-debt financial resources for the economic development of India. Additional Knowledge: · Agriculture (Option A): Though vital for the economy, it receives a relatively small percentage of FDI due to regulatory restrictions. · Manufacturing (Option B): Receives significant FDI under the 'Make in India' initiative but still trails behind the services sector.` },
  { s: `General Awareness`, q: `Assertion (A): Ajanta caves belong to the Buddhist tradition. Reason (R): They depict Jataka tales and Buddha's life.`, o: [`Both A and R are true and R explains A`, `Both A and R are true but R does not explain A`, `A is true but R is false`, `A is false but R is true`], e: `The correct answer is (A) Both A and R are true and R explains A Explanation: · Ajanta Caves, located in Maharashtra, are a series of rock-cut caves that are exclusively Buddhist. · The paintings and sculptures within depict stories from the Jataka tales and significant events from the life of Gautama Buddha. Information Booster: · There are 29-30 caves in Ajanta, which were built in two phases: the Satavahana period and the Vakataka period. Additional Knowledge: · Unlike Ellora, which has Hindu, Jain, and Buddhist caves, Ajanta is purely Buddhist.` },
  { s: `Quantitative Aptitude`, q: `A 20% decrease in the cost of sugar enables a consumer to purchase an additional 5 kg for 400. What was the initial price per kg?`, o: [`20`, `25`, `16`, `24`], e: `Given Price decrease = 20% Total Expenditure = 400 Extra Quantity = 5 kg Formula Used Expenditure = Price ×Consumption Solution Due to a 20% decrease in price, the consumer saves: Saving = 20% × 400 = 80 With this 80, the consumer buys an extra 5 kg of sugar. 80 Reduced Price per kg = = 16 5 Let the initial price be x. Reduced price is 80% of initial price (100% - 20%). 80% × x = 16 80 × x= 16 100 16 100 16 × 100 x = 80 x = 20 Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `The difference between two numbers is 1280. On dividing the larger by the smaller, the quotient is 7 and the remainder is 20. Find the smaller number.`, o: [`210`, `240`, `195`, `205`], e: `Given Difference between numbers = 1280 Quotient = 7 Remainder = 20 Formula Used Dividend = (Divisor × Quotient) + Remainder Solution Let the smaller number be y. Let the larger number be x. From the given difference: x - y = 1280 =>x = 1280 + y From the division condition: x = 7y + 20 Substitute the value of x: 1280 + y = 7y + 20 1280 - 20 = 7y - y 1260 = 6y y= 1260 6 y = 210 Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `The base of a right prism is a square of side 8 cm. If the height of the prism is 12 cm, find its volume in cubic centimetres.`, o: [`640`, `768`, `512`, `960`], e: `Given: Side of square base (a) = 8 cm Height of prism (h) = 12 cm Formula Used: Volume of prism = Base Area × Height Solution: First, we find the area of the square base: Area = a2 = 82 = 64 cm2 Now, calculate the volume: Volume = 64 × 12 Volume = 768 cm3 Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `A and B invest 80,000 and 60,000 respectively in a business. After 6 months, A increases his capital by 25%. If the total profit after 1 year is 55,000, what is B's share?`, o: [`22,000`, `20,000`, `25,000`, `30,000`], e: `Given: A's initial investment = 80,000 B's investment = 60,000 Time = 1 year (12 months) Total Profit = 55,000 Formula Used: Profit Ratio = Investment × Time Solution: A invests 80,000 for the first 6 months. Then A increases capital by 25%: New Capital = 80000 + (25% × 80000) = 80000 + 20000 = 100000 A invests 100,000 for the next 6 months. B invests 60,000 for 12 months. Calculate ratio of equivalent capitals: A's share : B's share = (80000 × 6 + 100000 × 6) : (60000 × 12) = (480000 + 600000) : 720000 = 1080000 : 720000 = 108 : 72 =3:2 B's share of profit: 2 B= × 55000 3+2 2 B = × 55000 5 B = 2 × 11000= 22000 Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `From a point 50m from the base of a tower, the angle of elevation is α where tan α = 1. From a point 20 m from the base (in the same line), the angle is β. Find tan β.`, o: [`2`, `2.5`, `1.5`, `3`], e: `Height h = 50 × tan α = 50 × 1 = 50 m. tan β = h / 20 = 50/20 = 2.5. Option B.` },
  { s: `Quantitative Aptitude`, q: `A group consists of 10 men and 10 women. A committee of 3 is selected. What is the probability that there are more women than men?`, o: [`0.5`, `0.35`, `0.45`, `0.6`], e: `Given: Men = 10, Women = 10, Total = 20 Committee size = 3 Condition: More women than men (i.e., 2 Women + 1 Man OR 3 Women) Formula Used: Probability = Favorable Outcomes Total Outcomes Solution: Total ways to select 3 people from 20: C 2 0 3 = 20 × 19 × 18 = 1140 3×2×1 Case 1: 2 Women and 1 Man C 10 2 ×10 C1 = 45 × 10 = 450 Case 2: 3 Women and 0 Men C 1 0 3 = 120 Total Favorable = 450 + 120 = 570 Probability: 570 P= = 0.5 1140 Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `A shopkeeper marks his goods 20% above CP but uses a weight of 800g instead of 1kg. What is his actual profit percentage?`, o: [`40%`, `50%`, `45%`, `35%`], e: `Given: Markup = 20% False weight = 800g for 1000g Formula Used: Profit % = SellingP rice - CostP rice × 100 CostP rice Solution: Let the Cost Price (CP) of 1g be 1. CP of 1000g = 1000. Marked Price (SP for customer) = 1000 + 20% of 1000 = 1200. However, the shopkeeper gives only 800g. Cost to shopkeeper for 800g = 800 × 1 = 800. Actual Profit = SP - Actual CP Profit = 1200 - 800 = 400 Profit Percentage: 400 × 100 = 50% 800 Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `A cylinder and a cone have the same volume and radius. Find the ratio of the height of the cylinder to the height of the cone.`, o: [`1:3`, `3:1`, `1:2`, `2:1`], e: `Given: Volume of Cylinder = Volume of Cone Radius of Cylinder = Radius of Cone = r Formula Used: Vol of Cylinder = r 2 hcy l Vol of Cone = 1 r 2 hcone 3 Solution: Equating the volumes: r2 hcyl = 1 r 2 hcone 3 Cancel \\pi r^2 from both sides: 1 h cyl = 3 h cone h cyl 1 = hcone 3 Ratio = 1:3 Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `The compound interest on a certain principal at 10% per annum for 2 years is 420. What is the simple interest on the same principal for the same time and rate?`, o: [`400`, `380`, `410`, `390`], e: `Given: Rate (R) = 10% Time (T) = 2 years Compound Interest (CI) = 420 Formula Used: R×R Effective Rate for CI = R + R + 100 P ×R×T SI = 100 Solution: Effective CI rate for 2 years at 10%: 10 + 10 + 10 × 10 = 21% 100 Let Principal be P. 21% × P = 420 21 × P = 420 100 P= 420 × 100 = 2000 21 Now, calculate Simple Interest: 2000 × 10 × 2 SI = 100 SI = 400 Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `If the difference between an angle and its supplement is 40, what is the angle?`, o: [`100`, `110`, `70`, `120`], e: `Given: Angle - Supplement = 40 Formula Used: Supplement of x = 180 - x Solution: Let the angle be x. Its supplement is 180 - x. According to the question: x - (180 - x) = 40 x - 180 + x = 40 2x = 220 x = 110 Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `Find the Mode of the data: 4, 7, 4, 3, 2, 4, 7, 7, 7, 8.`, o: [`4`, `7`, `3`, `8`], e: `Given Data: 4, 7, 4, 3, 2, 4, 7, 7, 7, 8 Formula Used Mode is the value that appears most frequently. Solution Frequency count: 4: 3 times 7: 4 times 3: 1 time 2: 1 time 8: 1 time Since 7 appears the most number of times (4 times), it is the mode. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `A solution of 60 liters contains 20% acid. How much pure acid (in liters) must be added to make the solution 40% acid?`, o: [`15`, `10`, `20`, `12`], e: `Given: Initial Volume = 60 liters Initial Acid % = 20% Target Acid % = 40% Formula Used: Total Acid = Target concentration Total Volume Solution: Initial Acid content = 20% × 60= 12 liters. Let x liters of pure acid be added. New Total Acid = 12 + x New Total Volume = 60 + x According to the condition: 12 + x 40 = 60 + x 100 12 + x = 0.4 60 + x 12 + x = 0.4(60 + x) 12 + x = 24 + 0.4x x - 0.4x = 24 - 12 0.6x = 12 12 x = = 20 0.6 Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `The average of 7 numbers is 40. The average of the first four is 35, and the last four is 45. What is the fourth number?`, o: [`30`, `35`, `40`, `45`], e: `Given Average of 7 numbers = 40 Average of first 4 numbers = 35 Average of last 4 numbers = 45 Formula Used Sum = Average × Count Solution Total sum of 7 numbers: S 7 = 7 × 40 = 280 Sum of first 4 numbers: Sfirst4 = 4 × 35 = 140 Sum of last 4 numbers: Slast4 = 4 × 45 = 180 Since the 4th number is included in both the first set and the last set, we can find it by: 4th Number = (Sf irst4 + Sl ast4 ) - S7 4th Number = (140 + 180) - 280 4th Number = 320 - 280 = 40 Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `Simplify: (3 1 + 1.25) × ( 4 - 0.3) ÷ (2 + 1 ) 4 5 2`, o: [`0.6`, `1.2`, `0.9`, `1.5`], e: `Given: 1 4 1 Expression: (3 + 1.25) × ( - 0.3) ÷ (2 + ) 4 5 2 Solution: 1 4 1 (3 + 1.25) × ( - 0.3) ÷ (2 + ) 4 5 2 13 4 1 = ( + 1.25) × ( - 0.3) ÷ (2 + ) 4 5 2 13 5 4 1 = ( + ) × ( - 0.3) ÷ (2 + ) 44 5 2 18 4 1 = × ( - 0.3) ÷ (2 + ) 45 2 94 1 = × ( - 0.3) ÷ (2 + ) 25 2 = 9 × ( 4 - 3 ) ÷ (2 + 1 ) 2 5 10 2 9 83 1 = × ( - ) ÷ (2 + ) 2 10 10 2 95 1 = × ÷ (2 + ) 2 10 2 91 1 = × ÷ (2 + ) 22 2 9 1 = ÷ (2 + ) 4 2 95 =÷ 42 92 = × 45 18 = 20 9 = 10 = 0.9` },
  { s: `Quantitative Aptitude`, q: `Two cars travel toward a destination. The distances travelled are in ratio 4:5. Car 1 speed is 60 kmph, Car 2 speed is 90 kmph. If they arrive with a time gap of 20 minutes, find the total distance travelled by both.`, o: [`270 km`, `240 km`, `180 km`, `300 km`], e: `Given Ratio of distances = 4:5 Speed of Car 1 (S1) = 60 kmph Speed of Car 2 (S2) = 90 kmph Time gap = 20 mins = 1/3 hr Formula Used Time = Distance / Speed Solution Let distances be 4x and 5x. Time taken by Car 1: T 1 = 4x x = 60 15 Time taken by Car 2: 5x x T 2 = = 90 18 Given difference in time is 20 minutes (1/3 hours). x x1 - = 15 18 3 6x - 5x 1 = 90 3 x1 = 90 3 x = 30 Total distance = 4x + 5x = 9x Total distance = 9 × 30 = 270 km Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `A, B, and C can complete a work in 20, 30, and 60 days respectively. A works daily, and B and C assist him every 3rd day. In how many days will the work be completed?`, o: [`10 days`, `12 days`, `15 days`, `18 days`], e: `Given Time taken by A = 20 days Time taken by B = 30 days Time taken by C = 60 days Formula Used Total Work = LCM of days Efficiency = Total Work / Days Solution Let Total Work = LCM(20, 30, 60) = 60 units. Efficiencies: A = 60/20 = 3 units/day B = 60/30 = 2 units/day C = 60/60 = 1 unit/day Work pattern for every 3 days: Day 1: A works alone = 3 units Day 2: A works alone = 3 units Day 3: A + B + C work = 3 + 2 + 1 = 6 units Total work in 3 days = 3 + 3 + 6 = 12 units. Number of cycles required: 60 60 = 5 cycles 12 Total days = 5 × 3 = 15 days Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `If a = 0.5, b = 0.3, c = 0.2, find the value of a2 - (b + c)2 . (a - b - c)(a + b + c)`, o: [`1`, `0`, `-1`, `0.5`], e: `Given: a = 0.5, b = 0.3, c = 0.2 Formula Used: x 2 - y2 = (x - y)(x + y) Solution Simplify the numerator: a 2 - (b + c)2 = (a - (b + c))(a + (b + c)) = (a - b - c)(a + b + c) Substitute this into the expression: (a - b - c)(a + b + c) (a - b - c)(a + b + c) Since the numerator and denominator are identical, they cancel out to give 1. Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `In a circle with center O, diameter AB is extended to P. A line from P touches the circle at T. If ∠APT = 30°, find ∠ABT.`, o: [`60°`, `90°`, `120°`, `30°`], e: `Tangent-radius: ∠OTP = 90°. In △OTP: ∠TOP = 60°. ∠AOT = 180° − 60° = 120° (central angle). ∠ABT = ∠AOT / 2 = 60°. Option A.` },
  { s: `Quantitative Aptitude`, q: `In a triangle, if the centroid is (2, 3) and the circumcenter is (5, 6), find the orthocenter.`, o: [`(-4, -3)`, `(-1, 0)`, `(3, 3)`, `(1, 1)`], e: `Given: Centroid (G) = (2, 3) Circumcenter (O) = (5, 6) Formula Used: The Centroid divides the line joining Orthocenter (H) and Circumcenter (O) in the ratio 2:1 internally. 2O + 1H G= 3 Solution: Rearranging the formula for H: 3G = 2O + H H = 3G - 2O Calculate x-coordinate: xH = 3(2) - 2(5) = 6 - 10 = -4 Calculate y-coordinate: yH = 3(3) - 2(6) = 9 - 12 = -3 Orthocenter H = (-4, -3) Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `Which equation represents a line parallel to the Y-axis?`, o: [`y = 3`, `x = 4`, `y = x`, `y = 2x+1`], e: `Given: Condition: Line parallel to Y-axis. Formula Used: Equation of a line parallel to Y-axis is x = k (constant). Solution: Check the options: A) y = 3 (Horizontal line, parallel to X-axis) B) x = 4 (Vertical line, parallel to Y-axis) C) y = x (Slant line) D) y = 2x+1 (Slant line) Option B satisfies the condition. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `If 2ⁿ = 128, find the value of 2ⁿ⁻².`, o: [`64`, `32`, `16`, `8`], e: `2ⁿ = 128 = 2⁷, so n = 7. 2ⁿ⁻² = 2⁵ = 32. Option B.` },
  { s: `Quantitative Aptitude`, q: `A metallic sphere of radius 6 cm is melted and drawn into a wire of diameter 2 cm. Find the length of the wire.`, o: [`36 cm`, `72 cm`, `144 cm`, `288 cm`], e: `Given: Radius of sphere (R) = 6 cm Diameter of wire = 2 cm Radius (r) = 1 cm Formula Used: Volume of Sphere = 4 R3 3 Volume of Cylindrical Wire = r2h Solution: Since volume remains constant on melting: 4 (6)3 = (1)2h 43 × 216 = 1 × h 3 4 × 72 = h h = 288 cm Final Answer So the correct answer is (d)` },
  { s: `Quantitative Aptitude`, q: `If cos = 3/5, and is acute, find 1 + tan2 .`, o: [`25/16`, `25/9`, `9/16`, `16/9`], e: `Given: cos = 3/5 Formula Used: 1 + tan2 = sec2 sec = 1 cos Solution: 3 5 Since cos = , then sec = . 5 3 Substitute into the identity: 1 + tan2 = ( 5 )2 3 25 = 9 Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `The mean of 5 observations x, x+2, x+4, x+6, x+8 is 15. Find the median.`, o: [`13`, `15`, `17`, `19`], e: `Given: Observations: x, x+2, x+4, x+6, x+8 Mean = 15 Formula Used: Median of AP series is the middle term. Solution: The data is already arranged in ascending order. Since there are 5 terms (odd), the median is the 3rd term. Median = x + 4. The Mean of an AP is also the middle term. So, Mean = Median. Given Mean = 15. Therefore, Median = 15. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `Two circles of radii 8 cm and 3 cm have their centers 13 cm apart. Find the length of the common external tangent.`, o: [`12 cm`, `10 cm`, `8 cm`, `11 cm`], e: `Given: R = 8 cm, r = 3 cm Distance (d) = 13 cm Formula Used: Length of tangent = d2 - (R - r)2 Solution: Substitute values: L = 132 - (8 - 3)2 L = 169 - 52 L = 169 - 25 L = 144 L = 12 cm Final Answer So the correct answer is (a)` },
  { s: `English Language`, q: `"The view of literature we are taught to preserve is relentlessly centered on the author..." What is the grammatical function of the clause "we are taught to preserve"? Read the passage and answer the questions: "Critical interpretation often begins with the assumption that a work's meaning is anchored in the person who produced it, as if literature ultimately speaks through a single consciousness and the trace of a private intention. The view of literature we are taught to preserve is relentlessly centered on the author--on biography, psychology, and motive. Yet to assign a text an Author is to place a boundary around it, to supply it with a final meaning, and to seal its possibilities. This way of thinking emerges from rationalist and capitalist traditions that elevate the individual as the primary unit of history, granting coherence and authority to personal origin. In practice, however, writing dissolves origins: it unravels the singular voice, and language speaks--not the author. To set aside the Author is not to discard meaning, but to resist the tyranny of one authoritative meaning. The text becomes a field of plural readings where interpretation remains open-ended rather than fixed. The unity of a text is located not at its source but at its destination; it is the reader--not the author--who activates meaning. This shift transfers power from creator to interpreter, from intended message to the endless play of signs within the text."`, o: [`Adverbial clause`, `Independent clause`, `Noun clause acting as object`, `Relative clause modifying "view"`], e: `The correct option is (d). Step-by-step explanation: 1) In the sentence, the main noun phrase is: "The view of literature ... is relentlessly centered on the author". 2) The words "we are taught to preserve" come immediately after "the view of literature" and give extra information about it (i.e., which view?). 3) Such a clause works like an adjective because it modifies a noun (here, it modifies the noun phrase "the view of literature"). Therefore, it is a relative (adjective) clause. 4) The implied relative pronoun is "that/which": "The view of literature (that) we are taught to preserve ...". Why other options are incorrect: (A) Adverbial clause modifies a verb/adjective/adverb (time, reason, condition, etc.). Here the clause modifies a noun phrase, not the verb. (B) Independent clause ` },
  { s: `English Language`, q: `Which sentence contains a correct use of the passive voice from the passage? Read the passage and answer the questions: "Critical interpretation often begins with the assumption that a work's meaning is anchored in the person who produced it, as if literature ultimately speaks through a single consciousness and the trace of a private intention. The view of literature we are taught to preserve is relentlessly centered on the author--on biography, psychology, and motive. Yet to assign a text an Author is to place a boundary around it, to supply it with a final meaning, and to seal its possibilities. This way of thinking emerges from rationalist and capitalist traditions that elevate the individual as the primary unit of history, granting coherence and authority to personal origin. In practice, however, writing dissolves origins: it unravels the singular voice, and language speaks--not the author. To set aside the Author is not to discard meaning, but to resist the tyranny of one authoritative meaning. The text becomes a field of plural readings where interpretation remains open-ended rather than fixed. The unity of a text is located not at its source but at its destination; it is the reader--not the author--who activates meaning. This shift transfers power from creator to interpreter, from intended message to the endless play of signs within the text."`, o: [`"The author determines the meaning."`, `"Language carries the author's intentions."`, `"Writing begins when the author speaks."`, `"The text is supplied with a final meaning."`], e: `The correct option is (d). Step-by-step explanation: 1) Passive voice is used when the focus is on the action/receiver, and the doer is either unknown or less important. Structure: Object + be + past participle (V3) (+ by + agent). 2) Option (D) says: "The text is supplied with a final meaning." Here, "the text" receives the action, and "is supplied" is be (is) + V3 (supplied), which is clearly passive. 3) The passage itself contains this passive construction: "to supply it with a final meaning," and option (D) correctly captures that idea in passive form. Why other options are incorrect: (A) "The author determines the meaning." is active (subject "author" performs the action). (B) "Language carries the author's intentions." is active (subject "language" performs the action). (C) "Writing ` },
  { s: `English Language`, q: `What does the word "relentlessly" most closely mean in the phrase "relentlessly centered on the author"? Read the passage and answer the questions: "Critical interpretation often begins with the assumption that a work's meaning is anchored in the person who produced it, as if literature ultimately speaks through a single consciousness and the trace of a private intention. The view of literature we are taught to preserve is relentlessly centered on the author--on biography, psychology, and motive. Yet to assign a text an Author is to place a boundary around it, to supply it with a final meaning, and to seal its possibilities. This way of thinking emerges from rationalist and capitalist traditions that elevate the individual as the primary unit of history, granting coherence and authority to personal origin. In practice, however, writing dissolves origins: it unravels the singular voice, and language speaks--not the author. To set aside the Author is not to discard meaning, but to resist the tyranny of one authoritative meaning. The text becomes a field of plural readings where interpretation remains open-ended rather than fixed. The unity of a text is located not at its source but at its destination; it is the reader--not the author--who activates meaning. This shift transfers power from creator to interpreter, from intended message to the endless play of signs within the text."`, o: [`With careful neutrality`, `In a forceful and controlling way`, `In a random manner`, `In a legal and formal way`], e: `The correct option is (b). Step-by-step explanation: 1) The phrase is: "relentlessly centered on the author". The word relentlessly means doing something without stopping, with persistent pressure, and often with a sense of being unyielding. (Hindi meaning: / ) 2) In context, it indicates that the teaching tradition keeps pushing interpretation back to the author in a strong, dominating, and controlling manner, not gently or occasionally. 3) Therefore, the closest meaning is "in a forceful and controlling way". Why other options are incorrect: (A) With careful neutrality suggests balanced calmness, but "relentlessly" suggests persistent pressure. (C) In a random manner is opposite; relentless is systematic and continuous. (D) In a legal and formal way relates to law/procedure, not persiste` },
  { s: `English Language`, q: `What is the best synonym for "inherent" in this sentence? "The need for an Author is treated as a cultural expectation rather than an inherent requirement of literature." Read the passage and answer the questions: "Critical interpretation often begins with the assumption that a work's meaning is anchored in the person who produced it, as if literature ultimately speaks through a single consciousness and the trace of a private intention. The view of literature we are taught to preserve is relentlessly centered on the author--on biography, psychology, and motive. Yet to assign a text an Author is to place a boundary around it, to supply it with a final meaning, and to seal its possibilities. This way of thinking emerges from rationalist and capitalist traditions that elevate the individual as the primary unit of history, granting coherence and authority to personal origin. In practice, however, writing dissolves origins: it unravels the singular voice, and language speaks--not the author. To set aside the Author is not to discard meaning, but to resist the tyranny of one authoritative meaning. The text becomes a field of plural readings where interpretation remains open-ended rather than fixed. The unity of a text is located not at its source but at its destination; it is the reader--not the author--who activates meaning. This shift transfers power from creator to interpreter, from intended message to the endless play of signs within the text."`, o: [`Adopted`, `Optional`, `Natural`, `Illusory`], e: `The correct option is (c). Step-by-step explanation: 1) The sentence says: "... rather than an inherent requirement of literature." The word inherent means existing naturally as an essential part; something that is built-in and cannot be separated from the thing itself. (Hindi meaning: / ) 2) Among the options, Natural matches this meaning because it indicates something that is by nature or essentially present in something. (Hindi meaning: / ) 3) Therefore, "inherent requirement" is best replaced by "natural requirement". Why other options are incorrect: (A) Adopted means chosen or taken up later (Hindi: / ), not naturally present. (B) Optional means not compulsory (Hindi: ), whereas inherent means essential. (D) Illusory means deceptive or unreal (Hindi: ), which is not the meaning of inh` },
  { s: `English Language`, q: `. According to the passage, what happens when the Author is set aside in interpretation? Read the passage and answer the questions: "Critical interpretation often begins with the assumption that a work's meaning is anchored in the person who produced it, as if literature ultimately speaks through a single consciousness and the trace of a private intention. The view of literature we are taught to preserve is relentlessly centered on the author--on biography, psychology, and motive. Yet to assign a text an Author is to place a boundary around it, to supply it with a final meaning, and to seal its possibilities. This way of thinking emerges from rationalist and capitalist traditions that elevate the individual as the primary unit of history, granting coherence and authority to personal origin. In practice, however, writing dissolves origins: it unravels the singular voice, and language speaks--not the author. To set aside the Author is not to discard meaning, but toCroespiysrtigthhet ©tyr2a0n2n6yAodf doan2e4a7uthoritative meaning. The text becomes a field of plural readings where interpretation remains open-ended rather than fixed. The unity of a text is located not at its source but at its destination; it is the reader--not the author--who activates meaning. This shift transfers power from creator to interpreter, from intended message to the endless play of signs within the text."`, o: [`The text becomes meaningless.`, `The text becomes open to multiple meanings.`, `The author's biography becomes central.`, `Meaning is restricted to history alone.`], e: `The correct option is (b). Step-by-step explanation: 1) The passage argues that focusing on the Author limits interpretation: it "places a boundary," "supplies a final meaning," and "seals possibilities." 2) When the Author is set aside, the text is no longer tied to one fixed intention. Instead, it becomes "a field of plural readings" where interpretation remains open-ended. 3) The passage clearly states that the unity of the text is at its destination (the reader), meaning the reader activates meaning, allowing multiple interpretations. 4) Hence, setting aside the Author makes the text open to multiple meanings. Why other options are incorrect: (A) The text becomes meaningless is wrong because the passage says meaning is not discarded; it is opened. (C) The author's biography becomes cen` },
  { s: `English Language`, q: `What is the one-word substitute for: "A genetic condition where a cell has only one copy of a particular chromosome instead of a pair"?`, o: [`Monosomy`, `Trisomy`, `Polyploidy`, `Aneuploidy`], e: `The correct option is (a). Explanation: Monosomy is a chromosomal abnormality in which a cell has only one copy of a particular chromosome instead of the normal pair, leading to a total of 2n - 1 chromosomes. (Hindi meaning: / ) It matches the definition because the question clearly states "one copy instead of a pair." Example: Turner syndrome is caused by monosomy of the X chromosome (45,X). Meanings of the other options: (B) Trisomy: Presence of three copies of a chromosome (2n + 1). (Hindi: ) (C) Polyploidy: Having more than two complete sets of chromosomes (e.g., 3n, 4n). (Hindi: ) (D) Aneuploidy: Any abnormal number of chromosomes due to gain or loss of one or more chromosomes (includes monosomy and trisomy). (Hindi: ) "So the correct answer is (a)"` },
  { s: `English Language`, q: `Which of the following is the correct spelling of the word?`, o: [`Prophylaxis`, `Prophylaxsis`, `Prophilaxis`, `Prophallaxis`], e: `The correct option is (a). Explanation: Option (A) Prophylaxis is the correctly spelt word. It means preventive treatment, especially medical steps taken to prevent a disease. (Hindi meaning: - / ) The spelling pattern is pro + phy + lax + is, and the standCaordpymriegdhitca©l t2e0rm26isAd"pdrao2p4h7ylaxis." Example: The doctor prescribed malaria prophylaxis before the international trip. Meanings of all the given options: (A) Prophylaxis: Prevention/precautionary treatment. (Hindi: ) (B) Prophylaxsis: Incorrect spelling; not a standard word. (Hindi: ) (C) Prophilaxis: Incorrect spelling; not a standard word. (Hindi: ) (D) Prophallaxis: Incorrect spelling; not a standard word. (Hindi: ) "So the correct answer is (a)"` },
  { s: `English Language`, q: `Meanings of all the given options: Prophylaxis: Prevention/precautionary treatment. (Hindi: रोकथाम) Prophylaxsis: Incorrect spelling; not a standard word. (Hindi: अशुद्ध वत नी) Prophilaxis: Incorrect spelling; not a standard word. (Hindi: अशुद्ध वत नी) Prophallaxis: Incorrect spelling; not a standard word. (Hindi: अशुद्ध वत नी) “So the correct answer is (a)”`, o: [`Narrate`, `Conceal`, `Retell`, `Describe`], e: `The correct option is (b). Explanation: Recount means to tell or narrate something in detail, especially an event or story. (Hindi meaning: / ) The antonym should convey the opposite idea: not telling, but hiding information. Conceal means to hide or keep something secret. (Hindi meaning: ) Example (given word): He recounted his travel experiences to the audience. Example (antonym): She concealed the facts to avoid criticism. Synonyms (Recount): narrate, relate, retell, recite. Antonyms (Recount): conceal, hide, suppress, withhold. Meanings of the other options: (A) Narrate: To tell a story. (Hindi: ) (C) Retell: To tell again. (Hindi: ) (D) Describe: To give details of something. (Hindi: ) "So the correct answer is (b)"` },
  { s: `English Language`, q: `Change the following from active to passive: Policy experts had repeatedly evaluated the framework's assumptions since its release.`, o: [`The framework's assumptions had been repeatedly evaluated by policy experts since its release.`, `The assumptions were being evaluated since its release by experts.`, `The assumptions had evaluated by policy experts since its release.`, `The assumptions had been under evaluation by experts since its release.`], e: `The correct option is (a). Explanation: The given sentence is in active voice and uses past perfect: "had evaluated". In passive voice, the object becomes the subject, and the structure becomes: Object + had been + V3 + by + Subject. Structure: Active voice: Subject + had + V3 + Object + (adverbs) + since + time point. Passive voice: Object + had been + V3 + (adverbs) + by + Subject + since + time point. So, "Policy experts" (doer) becomes the agent with by, and "the framework's assumptions" (object) becomes the new subject: "The framework's assumptions had been evaluated by policy experts ...". The adverb "repeatedly" is correctly placed before V3 for emphasis. Why other options are incorrect: (B) uses "were being evaluated" (past continuous passive), which changes the tense and is incorr` },
  { s: `English Language`, q: `Identify the misspelt word:`, o: [`Polysemy`, `Intertextuality`, `Similtude`, `Postmodernism`], e: `The correct option is (c). Explanation: Option (C) Similtude is misspelt. The correct spelling is Similitude, which means similarity or resemblance between two things. (Hindi meaning: / ) The incorrect word drops important letters, whereas the correct form contains "simili" and ends with "tude". Example: The similitude between the two theories is clear in their conclusions. Meanings of all the given options: (A) Polysemy: The condition of a word having multiple meanings. (Hindi: ) (B) Intertextuality: Relationship between texts through references and influence. (Hindi: ) (C) Similtude: Incorrect spelling; correct is "Similitude". (Hindi: ) (D) Postmodernism: A movement/approach that questions grand narratives and fixed meanings. (Hindi: -) Part of speech note: "Similitude" is a noun used t` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: The researcher's summary (1)/ was fill with precision (2)/ yet managed to obscure (3)/ more than clarify. (4)/`, o: [`(1)`, `(2)`, `(3)`, `(4)`], e: `The correct option is (b). Explanation of the error: Part (2) has the phrase: "was fill with precision". Here, "was" indicates a passive construction, so it must be followed by past participle (V3). The correct form is "was filled with precision", not "was fill". Correct sentence: The researcher's summary was filled with precision, yet managed to obscure more than clarify. Grammatical rule used: In passive voice, the structure is be verb + past participle (V3). Examples: "The work was completed on time." / "The forms were signed by the officer." Why other parts are correct: (1) "The researcher's summary" is a correct noun phrase. (3) "yet managed to obscure" is grammatically correct and shows contrast. (4) "more than clarify" is parallel and correct in comparison structure. Information boo` },
  { s: `English Language`, q: `Rearrange the following sentences in correct order to make a meaningful passage. 1. The applicant was requested to show valid identification. 2. Her biometric details were scanned and matched with the system. 3. She was guided to the waiting area after verification. 4. The reception desk recorded her entry in the visitor register.`, o: [`3-1-4-2`, `1-4-3-2`, `1-4-2-3`, `4-1-2-3`], e: `The correct option is (c). Explanation of the correct order (1-4-2-3): Sentence 1 logically comes first because the process begins when the applicant is asked to show valid identification. Sentence 4 follows naturally because after checking ID, the reception desk records the visitor's entry; this is a standard administrative step. Sentence 2 should come next because biometric scanning is a verification action that typically happens after entry details are recorded. Sentence 3 must be the last because it states "after verification," and verification is completed only after scanning and matching with the system. Grammar/logic clue: Phrases like "after verification" indicate that verification events must appear before that sentence in the sequence. "So the correct answer is (c)"` },
  { s: `English Language`, q: `Rearrange the following sentences in correct order to make a meaningful passage. (1) The applicant was requested to show valid identification. (2) Her biometric details were scanned and matched with the system. (3) She was guided to the waiting area after verification. (4) The reception desk recorded her entry in the visitor register.`, o: [`3-1-4-2`, `1-4-3-2`, `1-4-2-3`, `4-1-2-3`], e: `Order: 1 (show ID) → 4 (recorded entry) → 2 (biometric scan) → 3 (guided to waiting area). Option C (1-4-2-3).` },
  { s: `English Language`, q: `Rearrange the following sentences in correct order to make a meaningful passage. 1. Indicators are reviewed by dedicated monitoring units at regular intervals. 2. The model is repeatedly refined through multi-stakeholder consultations. 3. Deviations from targets are recorded on real-time dashboards. 4. Data systems are redesigned to improve inclusion.`, o: [`1-2-3-4`, `1-3-4-2`, `2-4-3-1`, `3-2-4-1`], e: `The correct option is (b). Explanation of the correct order (1-3-4-2): Sentence 1 sets the monitoring framework: indicators are reviewed regularly. This establishes the process. Sentence 3 naturally follows because monitoring leads to noting outcomes, and deviations are recorded on dashboards for visibility. Sentence 4 comes next as an action step taken after observing issues: data systems are redesigned to improve inclusion. Sentence 2 is best at the end because refining the model through multi-stakeholder consultations is an ongoing improvement step that logically follows system redesign and evidence from monitoring. Grammar/logic clue: A coherent passage often moves from observation (review/record) to intervention (redesign) and then to continuous improvement (refine through consultatio` },
  { s: `English Language`, q: `A sentence is provided in indirect speech. From the four given options, choose the one that most accurately conveys the sentence in its corresponding direct speech. The coordinator asked whether the files that were expected to be completed last month had been forwarded to the evaluation panel.`, o: [`"Did you forward the files meant to be completed last month to the evaluation panel?" the coordinator asked.`, `"Had the files expect last month been forwarded to the evaluation panel?" the coordinator asked.`, `"Have the files that were expected to be completed last month been forwarded to the evaluation panel?" the coordinator asked.`, `"Were the files due last month forwarded to the evaluation team?" the coordinator asked.`], e: `The correct option is (c). Explanation: The given sentence is in indirect speech and reports a yes/no question using "asked whether". To convert it into direct speech, we must restore the interrogative form and keep the meaning intact. Key conversion rules used: "asked whether/if" becomes a direct question with a question mark. The reported verb phrase "had been forwarded" indicates an action completed before a past reference point. In direct speech, the speaker's perspective can be represented using a natural present perfect passive question: "Have ... been forwarded?" The descriptive clause "that were expected to be completed last month" must remain to preserve the exact detail. Option (C) correctly forms the question: "Have the files ... been forwarded ...?" and keeps all essential info` },
  { s: `English Language`, q: `Fill in the blank with the most appropriate option: The updated software is ___ than the earlier build, cutting processing time significantly.`, o: [`efficient`, `most efficient`, `more efficient`, `efficiency`], e: `The correct option is (c). Explanation: The word "than" is a strong grammatical clue that the sentence requires a comparative degree. The adjective "efficient" becomes "more efficient" in comparative form because it is a multi-syllable adjective. (Hindi meaning of efficient: / ) Correct sentence: The updated software is more efficient than the earlier build, cutting processing time significantly. Example: This algorithm is more efficient than the previous version in handling large data sets. Why other options are incorrect: (A) efficient: Positive degree; does not fit with "than". (Hindi: ) (B) most efficient: Superlative degree used for comparison among three or more, not with "than". (Hindi: ) (D) efficiency: Noun form; the blank needs an adjective. (Hindi: ) "So the correct answer is (c` },
  { s: `English Language`, q: `Identify the correct spelling for "an official who supervises an exam."`, o: [`Invigilator`, `Envigilator`, `Invegilator`, `Invigelator`], e: `The correct option is (a). Explanation: Option (A) Invigilator is the correctly spelt word. It refers to an official who supervises candidates during an examination to prevent unfair means. (Hindi meaning: ) The standard spelling contains "vigil" (related to watchfulness), which matches the meaning of supervision. Example: The invigilator instructed the students to maintain silence in the examination hall. Meanings of all the given options: (A) Invigilator: Exam supervisor. (Hindi: ) (B) Envigilator: Incorrect spelling; not a standard word. (Hindi: ) (C) Invegilator: Incorrect spelling; not a standard word. (Hindi: ) (D) Invigelator: Incorrect spelling; not a standard word. (Hindi: ) "So the correct answer is (a)"` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: He had never visited (1)/ such a renowned exhibition (2)/ until he (3)/ visits the museum last winter. (4)/`, o: [`(1)`, `(2)`, `(3)`, `(4)`], e: `The correct option is (d). Explanation of the error: Part (4) says: "visits the museum last winter". The time expression "last winter" refers to a completed action in the past, so the verb must be in simple past: visited, not visits. Correct sentence: He had never visited such a renowned exhibition until he visited the museum last winter. Grammatical rule used: When a sentence includes a definite past time marker (yesCteorpdyaryig, hlats©t y2ea0r2,6laAstdwdain2t4e7r, in 2019), we use simple past. Example: "She met him last week." (Not "meets") Information booster: "Had never visited ... until ..." often uses past perfect in the first clause and simple past in the second clause to show the later past event that changed the situation. "So the correct answer is (d)"` },
  { s: `English Language`, q: `Choose the most suitable option to replace the highlighted part of the sentence: By the time we arrived at the venue, the speaker began the session.`, o: [`had begun`, `has begun`, `was beginning`, `is beginning`], e: `The correct option is (a). Explanation: The sentence begins with "By the time we arrived ...", which clearly shows that one past action happened before another past action. The arrival happened in the past, and the session started before that arrival. To show the earlier past action, we use past perfect. Grammatical rule used: When two actions occurred in the past and we want to show the earlier one, use: Past perfect (had + V3) for the earlier action + simple past for the later action. Correct sentence: By the time we arrived at the venue, the speaker had begun the session. Example: By the time the train arrived, the passengers had left the platform. Why other options are incorrect: (B) has begun: Present perfect does not fit with a completed past time context ("arrived"). (C) was beginni` },
  { s: `English Language`, q: `What is the one-word substitute for: "A narrative in which abstract ideas are represented through symbolic characters and events"?`, o: [`Allegory`, `Parable`, `Fable`, `Satire`], e: `The correct option is (a). Explanation: An Allegory is a narrative in which characters, events, and settings represent abstract ideas (such as truth, freedom, greed) and convey deeper moral, political, or philosophical meanings. (Hindi meaning: / ) It fits the definition because the question specifically mentions "abstract ideas" represented through symbolic elements. Example: "Animal Farm" is an allegory that represents political ideas through animal characters. Meanings of the other options: (B) Parable: A short story that teaches a moral lesson, often religious. (Hindi: ) (C) Fable: A short tale, usually with animals, teaching a moral. (Hindi: ) (D) Satire: Writing that uses humour/irony to criticize. (Hindi: ) "So the correct answer is (a)"` },
  { s: `English Language`, q: `Choose the correct meaning of the idiom given below: "Cut off one's nose to spite one's face"`, o: [`Be harmed by one's own plan`, `Celebrate too early`, `Escape by cleverness`, `Support someone else's success`], e: `The correct option is (a). Explanation: The idiom "Cut off one's nose to spite one's face" means doing something out of anger or revenge that ultimately harms oneself more than the other person. It refers to a self-defeating action taken to punish someone else, but it backfires. (Hindi idiom/meaning: ) Example: He resigned in anger to prove a point, but it ruined his career--he cut off his nose to spite his face. Other related idioms and meanings: Dig one's own grave: To do something that causes one's own failure. (Hindi: ) Shoot oneself in the foot: To harm one's own interests by mistake. (Hindi: ) Bit off more than one can chew: To take on more than one can handle. (Hindi: ) "So the correct answer is (a)"` },
  { s: `English Language`, q: `Convert the sentence provided below from its passive voice structure to an active voice structure: The compliance report has been filed by the legal unit after several revisions.`, o: [`The legal unit filed the compliance report after several revisions.`, `The legal unit is filing the compliance report after several revisions.`, `The legal unit has filed the compliance report after several revisions.`, `The legal unit had filed the compliance report after several revisions.`], e: `The correct option is (c). Explanation: The given sentence is in passive voice: "has been filed". The tense is present perfect passive because it uses has been + V3. Rules for conversion (Passive to Active): Identify the agent introduced by "by" (here, the legal unit) and make it the subject. Keep the same tense: present perfect becomes has/have + V3 in active. Move the object (here, the compliance report) after the verb as the object. Structure: Passive voice: Object + has/have been + V3 + by + Subject. Active voice: Subject + has/have + V3 + Object. Therefore: "The legal unit has filed the compliance report after several revisions." Why other options are incorrect: (A) changes the tense to simple past. (B) changes the tense to present continuous. (D) changes the tense to past perfect. "S` },
  { s: `English Language`, q: `A sentence is provided in direct speech. From the four given options, choose the one that most accurately conveys the sentence in its corresponding indirect speech. "Let it be stated that we will protect every inch of our border," declared the general.`, o: [`The general declare that they would protect every inch of their border.`, `The general declared that let it be stated they will protect the border.`, `The general declared that every inch of the border would Cboepbyeriingghtp©rot2e0c2te6dA. dda247`, `The general declared that they would protect every inch of their border.`], e: `The correct option is (d). Explanation: The given sentence is in direct speech with reporting verb "declared" (past). While converting to indirect speech, we follow standard narration rules. Rules applied: Reporting verb in past ("declared") generally causes backshifting of tense: will becomes would. Remove quotation marks and change the sentence into a that-clause. Pronouns change according to speaker: "we" becomes "they" (as per the subject used in indirect speech). "Our" becomes "their" to match "they". Thus, the correct indirect speech is: "The general declared that they would protect every inch of their border." Why other options are incorrect: (A) has wrong verb form "declare" instead of "declared". (B) keeps "let it be stated" improperly and uses "will" without backshift. (C) create` },
  { s: `English Language`, q: `Rearrange the following sentences in correct order to make a meaningful sentence. P: into workable public policy Q: translating research findings R: continues to be difficult S: in emerging democracies`, o: [`QPRS`, `SPRQ`, `QSRP`, `RQSP`], e: `The correct option is (a). Explanation: The sentence must begin with a meaningful subject phrase. Q: "translating research findings" works as a gerund phrase functioning as the subject. Then it must be completed by what is being translated: P: "into workable public policy" logically follows and completes the object of "translating." Next comes the main verb phrase: R: "continues to be difficult", which states the main idea about the subject. Finally, the place/context is added: S: "in emerging democracies". Correct sentence: Translating research findings into workable public policy continues to be difficult in emerging democracies. Grammar clue: In such rearrangements, a gerund phrase often forms a natural subject, followed by its complement, then the main verb, and finally the adverbial p` },
  { s: `English Language`, q: `Convert the sentence provided below from its passive voice structure to an active voice structure: The final draft has been approved by the committee.`, o: [`The committee has been approving the final draft.`, `The committee has approved the final draft.`, `The committee is approving the final draft.`, `The committee approved the final draft.`], e: `The correct option is (b). Explanation: The sentence is in present perfect passive: "has been approved". To convert passive to active while keeping the same tense, we change it to present perfect active: "has approved". Rules for conversion: Agent after by becomes the subject: the committee. Keep tense same: has been approved (passive) becomes has approved (active). Object becomes the object in active: the final draft. Structure: Passive voice: Object + has/have been + V3 + by + Subject. Active voice: Subject + has/have + V3 + Object. Why other options are incorrect: (A) present perfect continuous; changes tense and meaning. (C) present continuous; changes tense. (D) simple past; changes tense. "So the correct answer is (b)"` }
];

if (RAW.length !== 100) { console.error(`Expected 100 questions, got ${RAW.length}`); process.exit(1); }

async function seed() {
  console.log('Connecting to MongoDB...');
  await mongoose.connect(MONGO_URI);
  console.log('Connected.');

  let category = await ExamCategory.findOne({ name: 'Central', type: 'Central' });
  if (!category) {
    category = await ExamCategory.create({ name: 'Central', type: 'Central', description: 'Central government competitive exams' });
  }

  let exam = await Exam.findOne({ code: 'SSC-SSP' });
  if (!exam) {
    exam = await Exam.create({
      category: category._id,
      name: 'SSC Selection Post (Graduate Level)',
      code: 'SSC-SSP',
      description: 'Staff Selection Commission - Selection Post (Graduate Level)',
      isActive: true
    });
  }

  const PATTERN_TITLE = 'SSC Selection Post (Graduate Level)';
  let pattern = await ExamPattern.findOne({ exam: exam._id, title: PATTERN_TITLE });
  if (!pattern) {
    pattern = await ExamPattern.create({
      exam: exam._id, title: PATTERN_TITLE, duration: 60, totalMarks: 200, negativeMarking: 0.5,
      sections: [
        { name: REA, totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: GA,  totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: QA,  totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: ENG, totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 }
      ]
    });
  }

  const TEST_TITLE = 'SSC Selection Post (Graduation) - 28 July 2025 Shift-3 [Similar Paper]';
  await PracticeTest.deleteMany({ examPattern: pattern._id, title: TEST_TITLE });

  const questions = RAW.map((r, i) => ({
    questionText: r.q,
    questionImage: '',
    options: r.o,
    optionImages: ['', '', '', ''],
    correctAnswerIndex: KEY[i] - 1,
    explanation: r.e || '',
    section: r.s,
    tags: ['SSC', 'Selection Post', 'Phase XIII', 'Graduate', 'PYQ', '2025', 'Similar Paper'],
    difficulty: 'medium'
  }));

  const test = await PracticeTest.create({
    examPattern: pattern._id, title: TEST_TITLE, totalMarks: 200, duration: 60,
    accessLevel: 'FREE', isPYQ: true, pyqYear: 2025, pyqShift: '3',
    pyqExamName: 'SSC Selection Post Phase XIII (Graduate) - Similar Paper', questions
  });
  console.log(`Created PYQ PracticeTest: ${test._id} (${test.questions.length} questions)`);

  await mongoose.disconnect();
  console.log('Done.');
}

seed().catch(err => { console.error('Seed failed:', err); process.exit(1); });
